import React, { useState, useRef, useEffect } from "react";
import "./App.css";

function App() {
  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([]);
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState([]);

  const chatEndRef = useRef(null);
  const textareaRef = useRef(null);

  // Auto scroll
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chat]);

  // Auto expand textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
      textareaRef.current.style.height =
        textareaRef.current.scrollHeight + "px";
    }
  }, [message]);

  // New Chat
  const newChat = () => {
    if (chat.length > 0) {
      setHistory((prev) => [
        { title: chat[0]?.text?.slice(0, 20) || "Chat", data: chat },
        ...prev
      ]);
    }
    setChat([]);
  };

  // Load previous chat
  const loadChat = (item) => {
    setChat(item.data);
  };

  // Send Message (Streaming)
  const sendMessage = async () => {
    if (!message.trim() || loading) return;

    const userText = message;
    setMessage("");

    setChat((prev) => [...prev, { role: "user", text: userText }]);
    setLoading(true);

    try {
      const response = await fetch("http://localhost:8000/chat", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({ message: userText })
      });

      const reader = response.body.getReader();
      const decoder = new TextDecoder("utf-8");

      let botText = "";

      // Add empty bot message
      setChat((prev) => [...prev, { role: "bot", text: "" }]);

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value);
        botText += chunk;

        setChat((prev) => {
          const updated = [...prev];
          updated[updated.length - 1].text = botText;
          return updated;
        });
      }

    } catch (err) {
      setChat((prev) => [
        ...prev,
        { role: "bot", text: "⚠️ Error connecting to server." }
      ]);
    }

    setLoading(false);
  };

  return (
    <div className="app">

      {/* Sidebar */}
      <div className="sidebar">

        <div className="nike-logo">
          <img src="/nike.png" alt="nike" />
        </div>

        <div className="brand">
          <h2>SwooshAI</h2>
          <span>JustAsk</span>
        </div>

        {/* New Chat */}
        <button className="new-chat" onClick={newChat}>
          + New Chat
        </button>

        {/* Recent Chats */}
        <div className="recent">
          <h4>Recent Chats</h4>
          {history.map((item, i) => (
            <div
              key={i}
              className="chat-item"
              onClick={() => loadChat(item)}
            >
              {item.title}
            </div>
          ))}
        </div>

      </div>

      {/* Main */}
      <div className="main">

        {/* Topbar */}
        <div className="topbar">
          <h3>AI Assistant</h3>

          <div className="right-section">
            <img src="/quadrant.png" alt="quadrant" />
            <span className="status">● Online</span>
          </div>
        </div>

        {/* Chat Area */}
        <div className="chat-area">
          {chat.map((c, i) => (
            <div key={i} className={`msg ${c.role}`}>
              
              {/* Avatar */}
              <div className="avatar">
                {c.role === "user" ? "👤" : "🤖"}
              </div>

              <div className="bubble">{c.text}</div>
            </div>
          ))}

          {/* Typing indicator */}
          {loading && chat[chat.length - 1]?.role !== "bot" && (
            <div className="msg bot">
              <div className="avatar">🤖</div>
              <div className="bubble">...</div>
            </div>
          )}

          <div ref={chatEndRef}></div>
        </div>

        {/* Input */}
        <div className="input-box">
          <div className="input-box-inner">

            <textarea
              ref={textareaRef}
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="Message SwooshAI..."
              disabled={loading}
              onKeyDown={(e) => {
                if (e.key === "Enter" && !e.shiftKey) {
                  e.preventDefault();
                  sendMessage();
                }
              }}
            />

            <button onClick={sendMessage} disabled={loading}>
              ➤
            </button>

          </div>
        </div>

      </div>
    </div>
  );
}

export default App;
